mapper.select:
/* SmsMgmtMapper.getSmsSendList */ SELECT S.* ,FN_GET_CODENM('CMN0069', S.workType) AS workTypeNm ,FN_GET_CODENM('CMN0071', S.sendDivision) AS sendDivisionNm ,FN_GET_CODENM('CMN0068', S.result) AS resultNm ,DECODE(S.result, '100', TO_CHAR(S.REPORT_RECV_TIME, 'YYYYMMDDHH24MISS'), '') AS sendTime ,NVL(FN_GET_USRNM(S.procId), S.procId) AS procNm ,DECODE(S.sendYn, 'N', '실패', 'S', '대기', '성공') AS sendYnNm FROM ( SELECT T.SEND_REQ_DTTM AS sendReqDttm ,B.WORK_TYPE AS workType ,T.receiveNm ,T.mobileNo AS maskMobileNo ,T.SEND_DIVISION AS sendDivision ,T.CONTRACT_NUM AS contractNum ,T.PORTAL_USER_ID AS portalUserId ,T.MSP_USER_ID AS mspUserId ,T.RES_NO AS resNo ,B.TEMPLATE_ID AS templateId ,B.TEMPLATE_NM AS templateNm ,CASE WHEN D.DELIVER_TIME IS NOT NULL THEN 'Y' WHEN TO_DATE(T.SEND_REQ_DTTM, 'YYYYMMDDHH24MISS') > SYSDATE THEN 'S' ELSE 'N' END AS sendYn ,TRIM(D.RESULT) AS result ,T.SEND_CNT AS sendCnt ,D.REPORT_RECV_TIME ,T.REGST_ID AS procId ,NVL(D.MESSAGE, (SELECT Q.MESSAGE FROM AM2X_SUBMIT Q WHERE Q.MSG_ID = T.MSEQ)) AS text ,T.MSEQ AS mseq ,T.SEND_SEQ AS sendSeq FROM ( /* USR */ SELECT A.SEND_REQ_DTTM ,C.USR_NM AS receiveNm ,C.MBLPHN_NUM AS mobileNo ,A.SEND_DIVISION ,A.CONTRACT_NUM ,A.PORTAL_USER_ID ,A.MSP_USER_ID ,A.RES_NO ,A.SEND_CNT ,A.REGST_ID ,A.TEMPLATE_ID ,A.MSEQ ,A.SEND_SEQ FROM MSP_SMS_SEND_MST A ,CMN_USR_MST C WHERE A.MSP_USER_ID = C.USR_ID AND A.SEND_DIVISION = 'M2M' AND A.KT_SMS_YN = 'Y' ) T ,MSP_SMS_TEMPLATE_MST B ,AM2X_SUBMIT_LOG D WHERE T.TEMPLATE_ID = B.TEMPLATE_ID AND T.MSEQ = D.MSG_ID(+) AND T.SEND_REQ_DTTM BETWEEN #{searchStartDate} || '000000' AND #{searchEndDate} || '235959'
AND B.WORK_TYPE = #{searchWorkType}
AND TO_CHAR(B.TEMPLATE_ID) = #{searchTemplateNm}
AND UPPER(T.receiveNm) LIKE '%' || UPPER(#{searchValue}) || '%'
AND T.mobileNo = #{searchValue}
AND T.MSP_USER_ID = #{searchValue}
) S
AND S.sendYn = #{searchSendYn}
ORDER BY S.sendReqDttm DESC, S.workType, S.templateNm, S.receiveNm

/* SmsMgmtMapper.getMobileNo */
	SELECT C.MBLPHN_NUM AS mobileNo
	FROM   MSP_SMS_SEND_MST A
	      ,CMN_USR_MST C
	WHERE  A.MSP_USER_ID = C.USR_ID
	AND    A.SEND_DIVISION = #{sendDivision}
	AND    A.SEND_SEQ = #{sendSeq}
	AND    A.KT_SMS_YN = 'Y'

SELECT /* CmnCdMgmtMapper.getCommCombo */ GCM.CD_VAL AS value /* 코드 값 */ , GCM.CD_DSC AS text /* 코드 내용 */ FROM CMN_GRP_MST CGM , CMN_GRP_CD_MST GCM WHERE 1 = 1 AND CGM.GRP_ID = GCM.GRP_ID AND CGM.GRP_ID = #{grpId} AND GCM.CD_VAL IN ('mobileNo','receiveNm','mspUserId') AND GCM.USG_YN = 'Y'
AND GCM.ETC1 = #{etc1, jdbcType=VARCHAR}
AND GCM.ETC2 = #{etc2, jdbcType=VARCHAR}
AND GCM.ETC3 = #{etc3, jdbcType=VARCHAR}
AND GCM.ETC4 = #{etc4, jdbcType=VARCHAR}
AND GCM.ETC5 = #{etc5, jdbcType=VARCHAR}
AND GCM.ETC6 = #{etc6, jdbcType=VARCHAR}
ORDER BY TO_NUMBER(GCM.ETC1) ASC
ORDER BY TO_NUMBER(GCM.ETC2) ASC
ORDER BY TO_NUMBER(GCM.ETC3) ASC
ORDER BY TO_NUMBER(GCM.ETC4) ASC
ORDER BY TO_NUMBER(GCM.ETC5) ASC
ORDER BY TO_NUMBER(GCM.ETC6) ASC
ORDER BY GCM.CD_VAL ASC

/* M2mSmsMgmtMapper.getSmsSendListOld */ SELECT S.* ,FN_GET_CODENM('CMN0069', S.workType) AS workTypeNm ,FN_GET_CODENM('CMN0071', S.sendDivision) AS sendDivisionNm ,FN_GET_CODENM('CMN0068', S.result) AS resultNm ,DECODE(S.result, '100', TO_CHAR(S.REPORT_TIME, 'YYYYMMDDHH24MISS'), '') AS sendTime ,NVL(FN_GET_USRNM(S.procId), S.procId) AS procNm ,DECODE(S.sendYn, 'N', '실패', 'S', '대기', '성공') AS sendYnNm FROM ( SELECT T.SEND_REQ_DTTM AS sendReqDttm ,B.WORK_TYPE AS workType ,T.receiveNm ,T.mobileNo AS maskMobileNo ,T.SEND_DIVISION AS sendDivision ,T.CONTRACT_NUM AS contractNum ,T.PORTAL_USER_ID AS portalUserId ,T.MSP_USER_ID AS mspUserId ,T.RES_NO AS resNo ,B.TEMPLATE_ID AS templateId ,B.TEMPLATE_NM AS templateNm ,CASE WHEN D.SEND_TIME IS NOT NULL THEN 'Y' WHEN TO_DATE(T.SEND_REQ_DTTM, 'YYYYMMDDHH24MISS') > SYSDATE THEN 'S' ELSE 'N' END AS sendYn ,TRIM(D.RESULT) AS result ,T.SEND_CNT AS sendCnt ,D.REPORT_TIME ,T.REGST_ID AS procId ,NVL(D.TEXT, (SELECT Q.TEXT FROM MSG_QUEUE Q WHERE Q.MSEQ = T.MSEQ)) AS text ,T.MSEQ AS mseq ,T.SEND_SEQ AS sendSeq FROM ( /* USR */ SELECT A.SEND_REQ_DTTM ,C.USR_NM AS receiveNm ,C.MBLPHN_NUM AS mobileNo ,A.SEND_DIVISION ,A.CONTRACT_NUM ,A.PORTAL_USER_ID ,A.MSP_USER_ID ,A.RES_NO ,A.SEND_CNT ,A.REGST_ID ,A.TEMPLATE_ID ,A.MSEQ ,A.SEND_SEQ FROM MSP_SMS_SEND_MST A ,CMN_USR_MST C WHERE A.MSP_USER_ID = C.USR_ID AND A.SEND_DIVISION = 'M2M' AND A.KT_SMS_YN IS NULL ) T ,MSP_SMS_TEMPLATE_MST B ,MSG_RESULT D WHERE T.TEMPLATE_ID = B.TEMPLATE_ID AND T.MSEQ = D.MSEQ(+) AND T.SEND_REQ_DTTM BETWEEN #{searchStartDate} || '000000' AND #{searchEndDate} || '235959'
AND B.WORK_TYPE = #{searchWorkType}
AND TO_CHAR(B.TEMPLATE_ID) = #{searchTemplateNm}
AND UPPER(T.receiveNm) LIKE '%' || UPPER(#{searchValue}) || '%'
AND T.mobileNo = #{searchValue}
AND T.MSP_USER_ID = #{searchValue}
) S
AND S.sendYn = #{searchSendYn}
AND S.result = #{searchResult}
ORDER BY S.sendReqDttm DESC, S.workType, S.templateNm, S.receiveNm
